const tableId = 'notification-templates';

if (bundle.widgets.Table.get(tableId)) {
  bundle.widgets.Table.get(tableId).destroy();
  return;
}

const table = bundle.widgets.Table?.({ 
  container: K('content[Notification Table]').element(), 
  config: {
    title: 'Templates',
    integration: {
      kappSlug: K('kapp').slug(),
      formSlug: K('form').slug(),
      integrationName: 'Notification Templates',
      listProperty: 'submissions',
      errorProperty: 'Error'
    },
    // Transform the data to a single level map
    rowTransform: ({ Values, ...row }) => ({ ...row, ...Values }),
    columns: [
      {
        label: 'Submission Id',
        property: 'id',
        visible: false,
        toggleable: false,
      },{
        label: 'Status',
        property: 'status',
      },{
        label: 'Name',
        property: 'name',
      }
    ],
    addAction: {
      label: 'Add Template',
      onClick: function(tableApi) {
        tableApi.actions.subform({
          config: {
            kappSlug: 'admin-center',
            formSlug: 'notification-data',
            modalTitle: "Add Template",
            saveLabel: 'Create',
            values:{
              "Type": "Template"
            },
            onSave: function(data, api){
              api.submit(function(result){
                // Add row to the table so it appears immediately before the table reloads
                tableApi.addRow({
                  'Status': result.submission.values['Status'],
                  'Name': result.submission.values['Name'],                  
                });
                // Reload the table data in the background
                tableApi.reloadData();
                // Show toast and close subform
                bundle.utils.toastSuccess({ title: 'Notification added successfully' });
                api.destroy();
              });
            }
          },
        });
      }
    },
    rowActions: [
      {
        label: 'Edit Template',
        icon: 'pencil',
        onClick: function(row, index, tableApi){
          tableApi.actions.subform({
            config: {
              submissionId: row['id'],
              modalTitle: "Edit Template",
              saveLabel: 'Update',
              onSave: function(data, api){
                api.submit(function(result){
                  // Update the row in the table so it appears immediately before the table reloads
                  tableApi.updateRow({
                    'Status': result.submission.values['Status'],
                    'Name': result.submission.values['Name'],
                  }, index);
                  // Reload the table data in the background
                  tableApi.reloadData();
                  // Show toast and close subform
                  bundle.utils.toastSuccess({ title: 'Template updated successfully' });
                  api.destroy();
                });
              }
            },
          });
        }
      },{
        label: 'Delete Template',
        icon: 'trash',
        onClick: function(row, index, tableApi){
          bundle.utils.openConfirm({
            title: 'Delete Template',
            description: `Are you sure you want to delete the template: ${row['name']}?`,
            acceptLabel: 'Yes',
            accept: function(){
              K.api('DELETE', bundle.apiLocation() + '/submissions/' + row['id'], {
                complete: function(response){
                  if (response.status === 200) {
                    bundle.utils.toastSuccess({ title: 'Template was successfully deleted' });
                    tableApi.deleteRow(index);
                    tableApi.reloadData();
                  } else {
                    bundle.utils.toastError({ title: 'There was an error deleting the template' });
                  }
                }
              })

            }
          });
        }
      }
    ],
    pageSize: 100,
    pageSizes: [10,100,0],
    // Sort using the first column in ascending order by default
    defaultSort: [2, 'asc'],
    messages: {
      loading: 'Loading templates',
      empty: 'There are no templates',
      noMatches: 'No templates match your filter query'
    }
  }, 
  id: tableId
});

