const observer = new MutationObserver(() => {
  const modalEl = document.querySelector(`[data-scope="dialog"][data-part="content"]`);
  if (modalEl) {
    modalEl.classList.remove('md:w-screen-sm');
    modalEl.classList.add('md:w-screen-lg'); 
    //observer.disconnect(); // Stop watching once we found it
  }
});

observer.observe(document.body, { childList: true, subtree: true });
